import './App.scss';
import LoginForm from './components/imports/LoginForm.jsx';
import RegistrationForm from './components/imports/RegistrationForm.jsx';
import BaseLogin from './components/imports/BaseLogin';

import {BrowserRouter,Switch,Route} from 'react-router-dom';

function App()
 {
  return   (
    <div id="login">
      <div className="container">
        <div className="row login-box">
          <BrowserRouter>
            <Switch>
              <Route path="/logon"></Route>
            </Switch>
          </BrowserRouter>
          <BaseLogin/>
          <LoginForm/>
          <RegistrationForm/>
        </div>
      </div>
    </div>

  );
}

export default App;
